BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?owner WHERE {
  ?elem vocab:NamedElement_name "Alignment and Phasing System" .
  OPTIONAL { ?elem vocab:Element_owner ?owner . ?owner vocab:NamedElement_name ?ownerName }
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?qualifiedName WHERE {
  ?elem vocab:NamedElement_name ?name . 
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("alignment"))) 
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qualifiedName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?qualifiedName ?type WHERE {
  ?elem rdf:type vocab:package .
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS")))
  OPTIONAL { ?elem vocab:NamedElement_qualifiedName ?qualifiedName }
}
LIMIT 25
